import { useStore } from './store';
import { shallow } from 'zustand/shallow';
import { toast } from 'react-hot-toast';
import { PaperAirplaneIcon } from '@heroicons/react/24/solid';

const selector = (state) => ({
    nodes: state.nodes,
    edges: state.edges,
});

export const SubmitButton = () => {
    const { nodes, edges } = useStore(selector, shallow);

    const handleSubmit = async () => {
        if (nodes.length === 0) {
            toast.error("Cannot submit an empty pipeline. Please add some nodes.", { 
                icon: '🚀',
                style: {
                    borderRadius: '10px',
                    background: '#0D1117',
                    color: '#e2e8f0',
                    border: '1px solid #30363D'
                }
            });
            return;
        }

        const loadingToast = toast.loading('Analyzing pipeline structure...');

        try {
            const response = await fetch('http://localhost:8000/pipelines/parse', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ nodes, edges })
            });

            if (!response.ok) throw new Error('Backend analysis failed');

            const data = await response.json();

            toast.dismiss(loadingToast);

            // Success modal or toast with results
            toast.success(
                (t) => (
                    <div className="flex flex-col gap-2">
                        <p className="font-bold text-emerald-400">Pipeline Analyzed Successfully!</p>
                        <div className="grid grid-cols-2 gap-x-4 text-xs text-slate-300">
                            <span>Nodes: {data.num_nodes}</span>
                            <span>Edges: {data.num_edges}</span>
                            <span>Is DAG: <span className={data.is_dag ? 'text-emerald-400' : 'text-rose-400'}>{data.is_dag ? 'Yes' : 'No'}</span></span>
                        </div>
                    </div>
                ),
                { duration: 5000 }
            );

            // Save to history if valid
            const history = JSON.parse(localStorage.getItem('saved_flows') || '[]');
            const newEntry = {
                id: Date.now(),
                timestamp: new Date().toISOString(),
                nodes: nodes.length,
                edges: edges.length,
                is_dag: data.is_dag
            };
            localStorage.setItem('saved_flows', JSON.stringify([newEntry, ...history].slice(0, 10)));

        } catch (error) {
            toast.dismiss(loadingToast);
            toast.error(`Submission error: ${error.message}`);
        }
    };

    return (
        <button
            onClick={handleSubmit}
            className="flex items-center gap-2 px-6 py-3 bg-primary hover:bg-primary-hover text-white rounded-xl shadow-neon-primary transition-all duration-300 hover:scale-105 active:scale-95 font-bold uppercase tracking-widest text-xs group"
        >
            <PaperAirplaneIcon className="w-4 h-4 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
            Submit Pipeline
        </button>
    );
}
